parameters.body:
={

  "systemInstruction": {
    "parts": [{
      "text": "You are a senior executive assistant specializing in meeting preparation. You write sharp, concise, and actionable briefings for busy professionals. Given an event title, time, description, attendees, and location, you produce a single focused paragraph that helps the attendee walk into any meeting fully prepared. Your tone is professional and confident. You never repeat the event title or time in your response. You never use bullet points. You always write in flowing prose under 120 words."
    }]
  },
  "contents": [{
    "role": "user",
    "parts": [{
      "text": "Event Title: {{ $json.summary }}\nTime: {{ $json.start.dateTime }}\nDescription: {{ $json.description || 'No description provided' }}\nAttendees: {{ $json.attendees ? $json.attendees.map(a => a.email).join(', ') : 'Not specified' }}\nLocation: {{ $json.location || 'Not specified' }}\n\nWrite a professional one-paragraph meeting preparation summary for this event. Include what this meeting is likely about based on the title and description, 2-3 specific talking points or questions to prepare in advance, any materials or context the attendee should review beforehand, and what outcome or decision to aim for by the end of the meeting. Be direct, actionable, and professional. Write in flowing prose only. Keep it under 120 words."
    }]
  }],
  "generationConfig": {
    "maxOutputTokens": 500,
    "temperature": 0.4
  }
}

parameters.jsCode:
// Parse Gemini API response
// The HTTP Request response contains the Gemini reply.
// We embedded _eventTitle and _eventTime in the request body so Gemini echoes them back — but that's unreliable.
// Instead we use $('Loop Over Events').item to get the original calendar item for THIS batch item.
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  // Gemini response: candidates[0].content.parts[0].text
  const summaryText = item.json.candidates?.[0]?.content?.parts?.[0]?.text || 'Summary not available';

  // Get original calendar event from the loop node
  const loopItem = $('Loop Over Events').item;
  const eventTitle = loopItem?.json?.summary || 'Untitled Event';
  const eventTime = loopItem?.json?.start?.dateTime || loopItem?.json?.start?.date || '';

  results.push({
    json: {
      eventTitle,
      eventTime,
      aiSummary: summaryText
    }
  });
}

return results;

const items = $input.all();

// Format time helper
function formatTime(isoString) {
  if (!isoString) return '';
  const d = new Date(isoString);
  return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
}

function formatDate(isoString) {
  if (!isoString) return '';
  const d = new Date(isoString);
  return d.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
}

const meetingCount = items.length;
const dateLabel = items[0]?.json?.eventTime ? formatDate(items[0].json.eventTime) : 'Tomorrow';

let cardsHtml = '';

for (const item of items) {
  const title = item.json.eventTitle || 'Untitled Meeting';
  const time = item.json.eventTime ? formatTime(item.json.eventTime) : 'All Day';
  const summary = item.json.aiSummary || 'No summary available.';

  cardsHtml += `
  <div style="margin-bottom:28px;border:1px solid #e8ecf0;border-radius:10px;overflow:hidden;">
    <div style="background:#f7f9fc;padding:16px 20px;border-bottom:1px solid #e8ecf0;">
      <p style="margin:0 0 3px;font-size:11px;letter-spacing:1.5px;text-transform:uppercase;color:#4f8ef7;font-weight:600;">${time}</p>
      <h2 style="margin:0;font-size:17px;color:#1a202c;font-weight:700;">${title}</h2>
    </div>
    <div style="padding:18px 20px;">
      <p style="margin:0;font-size:14px;color:#4a5568;line-height:1.75;">${summary}</p>
    </div>
  </div>`;
}

const html = `
<html>
<body style="margin:0;padding:0;background:#f0f2f5;font-family:Arial,sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f2f5;padding:32px 16px;">
  <tr><td align="center">
    <table width="620" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #e2e6ea;">

      <!-- HEADER -->
      <tr><td style="background:#1a1a2e;padding:36px 40px 28px;">
        <p style="margin:0 0 8px;color:#a0aec0;font-size:11px;letter-spacing:2px;text-transform:uppercase;">Meeting Intelligence</p>
        <h1 style="margin:0 0 6px;color:#ffffff;font-size:26px;font-weight:700;">Tomorrow's Briefing</h1>
        <p style="margin:0;color:#718096;font-size:13px;">${dateLabel} &nbsp;·&nbsp; ${meetingCount} meeting${meetingCount !== 1 ? 's' : ''} scheduled</p>
      </td></tr>

      <!-- BODY -->
      <tr><td style="padding:32px 40px;">
        ${cardsHtml}
      </td></tr>

      <!-- FOOTER -->
      <tr><td style="background:#f7f9fc;border-top:1px solid #e8ecf0;padding:20px 40px;">
        <table width="100%"><tr>
          <td style="font-size:12px;color:#a0aec0;">Generated by Meeting Prep Bot</td>
          <td align="right" style="font-size:12px;color:#a0aec0;">Powered by Gemini AI · n8n</td>
        </tr></table>
      </td></tr>

    </table>
  </td></tr>
</table>
</body>
</html>`;

return [{ json: { html } }];
